B.a_3=new A.m(B.x,"Kontrol listeleri sabit dil kal\u0131plar\u0131n\u0131 takip eder","Havac\u0131l\u0131k kontrol listeleri son derece standartla\u015ft\u0131r\u0131lm\u0131\u015f bir dil yap\u0131s\u0131 kullan\u0131r. G\xfcnl\xfck \u0130ngilizcenin aksine, kontrol listesi dili **s\u0131k\u0131\u015ft\u0131r\u0131lm\u0131\u015f ve kesin**tir \u2014 her kelime do\u011fruluk ve k\u0131sal\u0131k i\xe7in se\xe7ilmi\u015ftir.\n\nBo\u015fluk doldurma sorular\u0131, her kontrol listesi \xf6\u011fesi i\xe7in do\u011fru teknik terim veya ifadeyi bilip bilmedi\u011finizi s\u0131nar.",null,null,null)
