B.a2x=s(["Both are turned ON","One is ON and one is OFF","Both are turned OFF","The position does not matter"],t.s)
B.alU=new A.r(-101,B.P,607,"During wet motoring, what is the position of the ignition systems?",B.a2x,2,B.p,null,null,null)
B.a5O=s(["Engine speed only","The starter motor temperature","The exhaust nozzle for signs of fuel","The HP rotor vibration"],t.s)
