B.X3=new A.m(B.x,"CRM neden hayati \xf6nem ta\u015f\u0131r","**Crew Resource Management (CRM)**, kaza \xf6nlemede kritik bir fakt\xf6rd\xfcr. Ara\u015ft\u0131rmalar, u\xe7ak kazalar\u0131n\u0131n b\xfcy\xfck \xe7o\u011funlu\u011funun teknik ar\u0131zadan de\u011fil **ileti\u015fim ve ekip koordinasyonu** yetersizli\u011finden kaynakland\u0131\u011f\u0131n\u0131 g\xf6stermektedir.\n\nEtkili CRM dili \u015funlar\u0131 i\xe7erir: a\xe7\u0131k \xe7a\u011fr\u0131 y\xf6ntemi, challenge-response, sterile cockpit kural\u0131na uyum ve g\xfcvenlik endi\u015felerini iletebilme.",null,null,null)
