B.XV=new A.m(B.x,"Servis hatalar\u0131 nas\u0131l y\xf6netilir?","Kabin hizmetlerinde aksakl\u0131klar (eksik yemek se\xe7ene\u011fi, sistem ar\u0131zas\u0131, koltuk sorunu) ya\u015fanabilir. Bunlar\u0131 profesyonel bir dille y\xf6netmek, m\xfc\u015fteri memnuniyetini ve g\xfcveni korur.",null,null,null)
B.a_b=new A.m(B.v,"Servis Hatas\u0131 \u0130fadeleri",'"I sincerely apologise for the inconvenience."\n"Unfortunately, your pre-ordered meal was not loaded onto the aircraft. I\'m sorry for this error."\n"I\'m afraid the in-flight entertainment system in your seat is not functioning. I\'ll try to reset it."\n"We will report this issue to the airline and ensure you are compensated."\n"As an apology, may I offer you [complimentary item]?"\n"Your feedback is very important to us. I\'ll inform my supervisor."',null,null,null)
