B.a_H=new A.m(B.x,"Neden mevzuat \u0130ngilizcesi \xf6\u011frenilmeli",'EASA y\xf6netmelikleri (Part-66, Part-145, Part-M) \u0130ngilizce olarak yay\u0131mlan\u0131r ve T\xfcrk SHGM mevzuat\u0131 da bu belgelere at\u0131f yapar.\n\nBir teknisyen olarak lisans yenileme, yetki kazanma ve denetim s\xfcre\xe7lerinde bu belgeleri okuyup anlayabilmek zorunludur. "Shall", "may", "must" gibi modal fiillerin mevzuattaki anlamlar\u0131 g\xfcnl\xfck \u0130ngilizceden farkl\u0131d\u0131r.',null,null,null)
B.VT=new A.m(B.v,"\ud83d\udcd0 Mevzuatta Modal Fiil Hiyerar\u015fisi",'**Zorunluluk seviyeleri (EASA/ICAO standartlar\u0131):**\n\u2022 **shall** \u2014 kesin yasal zorunluluk (en g\xfc\xe7l\xfc)\n\u2022 **must** \u2014 zorunluluk (d\xfczenleyici \u015fart)\n\u2022 **should** \u2014 tavsiye edilen iyi uygulama\n\u2022 **may** \u2014 izin verilen se\xe7enek\n\n**Dikkat:** G\xfcnl\xfck \u0130ngilizcede "shall" eski moda; mevzuatta ise **zorunlu**dur.\n\n**Part-66 anahtar terimleri:**\n\u2022 holder of a licence \u2014 lisans sahibi\n\u2022 certifying staff \u2014 onaylay\u0131c\u0131 personel\n\u2022 scope of work \u2014 i\u015f kapsam\u0131\n\u2022 authorisation \u2014 yetki\n\u2022 compliance \u2014 uyumluluk\n\u2022 findings \u2014 bulgular\n\u2022 corrective action \u2014 d\xfczeltici faaliyet',null,null,null)
B.PZ=new A.a1("The holder of a Part-66 licence shall ensure that the licence is accessible when performing maintenance.","Part-66 lisans\u0131n\u0131n sahibi, bak\u0131m ger\xe7ekle\u015ftirirken lisans\u0131n eri\u015filebilir olmas\u0131n\u0131 sa\u011flamal\u0131d\u0131r (yasal zorunluluk).","shall ensure")
B.PL=new A.a1("Certifying staff shall not certify maintenance they have not performed or directly supervised.","Onaylay\u0131c\u0131 personel, bizzat ger\xe7ekle\u015ftirmedi\u011fi veya do\u011frudan denetlemedi\u011fi bak\u0131m\u0131 onaylamamal\u0131d\u0131r.","shall not certify")
